INSERT INTO public.qc_issues (id, sample_id, batch_id, test_name, measured_value, expected_value, standard_deviation, z_score, priority, status, investigator, detected_at, updated_at, issue_description, root_cause, capa_action_plan, ai_analysis, comments, history) VALUES
('QC-2026-001', 'SMP-HPLC-092', 'BTH-HP-15', 'HPLC Potency', 95.8, 98.5, 0.8, -3.375, 'Medium', 'Resolved', 'Dr. Sarah Jenkins', '2026-06-15T09:30:22Z', '2026-06-16T15:00:00Z', 'HPLC potency benchmark dropped to 95.8% (expected 98.5% ± 0.8%), presenting a z-score of -3.38. This is a severe 1_3s Westgard limit violation, marking the analytical run as out-of-control.', 'Column particulate blockage and mobile phase aging led to abnormal peak broadening and low recovery.', 'Flushed chromatographic column with 100% methanol overnight, prepared and validated fresh acetonitrile/water mobile phase, and re-calibrated index using a fresh reference standard.', '### Gemini Expert CAPA Analysis:\n- **Immediate Contamination Audit**: Standard peaks are broadened. Suspect column pressure increase. Please check column frit back-pressure.\n- **Recommended SOP Intervention**:\n  1. Isolate the batch immediately. Do not release clinical dosage.\n  2. Flush the reverse-phase column.\n  3. Verify flow rate stability to rule out pump seal wear.', '[{"id":"c1","author":"Dr. Sarah Jenkins","text":"Successfully flushed column; post-wash calibration peaks look extremely sharp again.","createdAt":"2026-06-15T18:22:00Z"},{"id":"c2","author":"Emily Carter","text":"Verified. Post-recalibration control sample returned a potency of 98.6%. Closing issue.","createdAt":"2026-06-16T14:50:00Z"}]'::jsonb, '[{"id":"h1","status":"Open","changedBy":"Dr. Sarah Jenkins","text":"QC issue auto-detected from HPLC Potency Run #5.","createdAt":"2026-06-15T09:30:22Z"},{"id":"h2","status":"Under Investigation","changedBy":"Dr. Sarah Jenkins","text":"Investigation initiated. Pressure verified on HPLC System G.","createdAt":"2026-06-15T10:15:00Z"},{"id":"h3","status":"Resolved","changedBy":"Dr. Sarah Jenkins","text":"Re-certified calibration run passed within acceptable ±1.5SD.","createdAt":"2026-06-16T15:00:00Z"}]'::jsonb),
('QC-2026-002', 'SMP-PCR-449', 'BTH-PC-08', 'RT-PCR Viral Load', 3.82, 3, 0.2, 4.1, 'Urgent', 'Under Investigation', 'Dr. Kenji Tanaka', '2026-06-14T14:45:00Z', '2026-06-14T15:20:00Z', 'Positive run control standard detected with viral amplification log value of 3.82 against target 3.00 ± 0.20 (Z-score = 4.1). Exceeds 1-3s Westgard limit, indicating a high-risk replication or template cross-contamination event.', NULL, NULL, '### Gemini PCR Contamination Diagnostics:\n- **Westgard Pattern Detected**: Spike is isolated and extremely high (+4.1SD). Points to random contamination rather than systematic thermal cycler drift.\n- **Actionable CAPA Suggestions**:\n  1. Discard current master mix vial. Aliquots have likely been compromised by aerosol micro-particles during prep.\n  2. Execute UV decontamination protocol on Biosafety Cabinet Class II.\n  3. Recalibrate and run negative controls (NTC) in triplicate to guarantee absolute baseline clearance.', '[{"id":"c11","author":"Dr. Kenji Tanaka","text":"Master mix aerosol contamination highly likely. Will run negative controls first thing tomorrow to inspect biosafety cabinet airflow.","createdAt":"2026-06-14T16:00:00Z"}]'::jsonb, '[{"id":"h11","status":"Open","changedBy":"Dr. Kenji Tanaka","text":"Auto-detected failure on positive standards RT-PCR run #5.","createdAt":"2026-06-14T14:45:00Z"},{"id":"h12","status":"Under Investigation","changedBy":"Dr. Kenji Tanaka","text":"Assay isolated. No clinical patient results were processed or reported.","createdAt":"2026-06-14T15:20:00Z"}]'::jsonb),
('QC-2026-003', 'SMP-EL-990', 'BTH-EL-22', 'ELISA IgG', 1.34, 1.5, 0.1, -1.6, 'Medium', 'Open', 'Emily Carter', '2026-06-11T11:15:00Z', '2026-06-11T12:00:00Z', 'ELISA positive control returns 1.34, which mathematically is only -1.60SD from mean. However, 10 consecutive runs have fallen consistently below the mean of 1.50, constituting a 10_X Westgard systematic shift violation.', NULL, NULL, NULL, '[]'::jsonb, '[{"id":"h31","status":"Open","changedBy":"Emily Carter","text":"QC issue generated due to systematic drift (10_X rule).","createdAt":"2026-06-11T11:15:00Z"}]'::jsonb);
